Here's how to structure your MSTest tests for `DataFetcher`:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Fake handler to control HttpClient behavior in tests
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;
        public FakeHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new FakeHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_OnFailureStatus()
    {
        var handler = new FakeHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.InternalServerError)));

        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenAlreadyCanceled()
    {
        var handler = new FakeHandler((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK));
        });

        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<OperationCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsTaskCanceled_WhenTimeoutExpires()
    {
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct); // simulate slow server
            return new HttpResponseMessage(HttpStatusCode.OK);
        });

        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // safety net — fail if test hangs
    public async Task FetchAsync_PassesCancellationToken_ToHttpClient()
    {
        CancellationToken captured = default;
        var handler = new FakeHandler((_, ct) =>
        {
            captured = ct;
            return Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("ok")
            });
        });

        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();

        await fetcher.FetchAsync("https://example.com", cts.Token);

        Assert.IsTrue(captured.CanBeCanceled,
            "CancellationToken should be forwarded to HttpClient");
    }
}
```

**Key patterns used:**

- **`FakeHandler`** — subclass `HttpMessageHandler` to control responses without a real HTTP server or mocking library.
- **Pre-canceled token** — `cts.Cancel()` before calling, asserts `OperationCanceledException`.
- **Timeout simulation** — `CancellationTokenSource(TimeSpan)` + a slow handler proves your code respects cancellation.
- **`[Timeout(5000)]`** — MSTest safety net that fails the test if it hangs, preventing CI stalls.
- **Token forwarding** — captures the token inside the handler to verify it's actually passed through.
